/// StaticTag type for parsed tag data.
#[derive(Debug, Clone)]
pub enum StaticTag {
    Condition {
        var: String,
        neg: bool,
    },
    Multiplier {
        var: String,
        div: f64,
        limit: Option<f64>,
        base: f64,
    },
    MultiplierThreshold {
        var: String,
        threshold: f64,
        upper: bool,
    },
    PerStat {
        stat: String,
        div: f64,
        limit: Option<f64>,
        base: f64,
    },
    StatThreshold {
        stat: String,
        threshold: f64,
        upper: bool,
    },
    GlobalEffect {
        effect_type: String,
        unscalable: bool,
    },
    SkillName {
        name: String,
    },
    SkillId {
        id: String,
    },
    SkillType {
        skill_type: u32,
    },
    SlotName {
        slot_name: String,
        neg: bool,
    },
    SocketedIn {
        slot_name: String,
    },
    ItemCondition {
        var: String,
        neg: bool,
    },
    ActorCondition {
        actor: String,
        var: String,
        neg: bool,
    },
    Limit {
        limit: f64,
    },
    ModFlagOr {
        mod_flags: ModFlags,
    },
    KeywordFlagAnd {
        keyword_flags: KeywordFlags,
    },
    Unknown {
        raw: String,
    },
}

impl StaticTag {
    /// Convert to the runtime ModTag type.
    pub fn to_mod_tag(&self) -> ModTag {
        match self {
            StaticTag::Condition { var, neg } => ModTag::Condition {
                var: var.clone(),
                neg: *neg,
            },
            StaticTag::Multiplier {
                var,
                div,
                limit,
                base,
            } => ModTag::Multiplier {
                var: var.clone(),
                div: *div,
                limit: *limit,
                base: *base,
            },
            StaticTag::MultiplierThreshold {
                var,
                threshold,
                upper,
            } => ModTag::MultiplierThreshold {
                var: var.clone(),
                threshold: *threshold,
                upper: *upper,
            },
            StaticTag::PerStat {
                stat,
                div,
                limit,
                base,
            } => ModTag::PerStat {
                stat: stat.clone(),
                div: *div,
                limit: *limit,
                base: *base,
            },
            StaticTag::StatThreshold {
                stat,
                threshold,
                upper,
            } => ModTag::StatThreshold {
                stat: stat.clone(),
                threshold: *threshold,
                upper: *upper,
            },
            StaticTag::GlobalEffect {
                effect_type,
                unscalable,
            } => ModTag::GlobalEffect {
                effect_type: effect_type.clone(),
                unscalable: *unscalable,
            },
            StaticTag::SkillName { name } => ModTag::SkillName { name: name.clone() },
            StaticTag::SkillId { id } => ModTag::SkillId { id: id.clone() },
            StaticTag::SkillType { skill_type } => ModTag::SkillType {
                skill_type: *skill_type,
            },
            StaticTag::SlotName { slot_name, neg } => ModTag::SlotName {
                slot_name: slot_name.clone(),
                neg: *neg,
            },
            StaticTag::SocketedIn { slot_name } => ModTag::SocketedIn {
                slot_name: slot_name.clone(),
            },
            StaticTag::ItemCondition { var, neg } => ModTag::ItemCondition {
                var: var.clone(),
                neg: *neg,
            },
            StaticTag::ActorCondition { actor, var, neg } => ModTag::ActorCondition {
                actor: actor.clone(),
                var: var.clone(),
                neg: *neg,
            },
            StaticTag::Limit { limit } => ModTag::Limit { limit: *limit },
            StaticTag::ModFlagOr { mod_flags } => ModTag::ModFlagOr {
                mod_flags: *mod_flags,
            },
            StaticTag::KeywordFlagAnd { keyword_flags } => ModTag::KeywordFlagAnd {
                keyword_flags: *keyword_flags,
            },
            StaticTag::Unknown { .. } => ModTag::Condition {
                var: "_unsupported".to_string(),
                neg: false,
            },
        }
    }
}

/// Capitalize the first letter of a string.
fn capitalize_first(s: &str) -> String {
    let mut chars = s.chars();
    match chars.next() {
        None => String::new(),
        Some(c) => c.to_uppercase().collect::<String>() + chars.as_str(),
    }
}

/// Find the earliest regex match among patterns, breaking ties by longest match, then longest pattern.
/// Returns (pattern_index, captures, match_start, match_end).
fn scan_regex<'a, T>(
    line: &'a str,
    patterns: &[(Lazy<Regex>, T)],
) -> Option<(usize, regex::Captures<'a>, usize, usize)>
where
    T: std::fmt::Debug,
{
    let mut best: Option<(usize, usize, usize, usize, usize)> = None; // (idx, start, end, match_len, pat_len)

    for (i, (re, _)) in patterns.iter().enumerate() {
        if let Some(m) = re.find(line) {
            let start = m.start();
            let end = m.end();
            let match_len = end - start;
            let pat_len = re.as_str().len();

            let is_better = match best {
                None => true,
                Some((_, bs, be, bml, bpl)) => {
                    start < bs
                        || (start == bs && match_len > bml)
                        || (start == bs && match_len == bml && pat_len > bpl)
                }
            };

            if is_better {
                best = Some((i, start, end, match_len, pat_len));
            }
        }
    }

    if let Some((idx, start, end, _, _)) = best {
        let re = &patterns[idx].0;
        let caps = re.captures(line)?;
        Some((idx, caps, start, end))
    } else {
        None
    }
}

/// Scan regex patterns stored in a Vec (for Lazy<Vec<...>> data).
fn scan_regex_vec<'a, T>(
    line: &'a str,
    patterns: &[(Lazy<Regex>, T)],
) -> Option<(usize, regex::Captures<'a>, usize, usize)>
where
    T: std::fmt::Debug,
{
    scan_regex(line, patterns)
}

/// Find the earliest plain-text substring match among keys in a HashMap.
/// Returns (key, start, end, entry).
fn scan_plain<'a, V>(
    line: &str,
    map: &'a HashMap<&str, V>,
) -> Option<(&'a str, usize, usize, &'a V)> {
    let lower = line.to_lowercase();
    let mut best: Option<(&'a str, usize, usize, &'a V)> = None;

    for (key, val) in map.iter() {
        if let Some(pos) = lower.find(key) {
            let end = pos + key.len();
            let is_better = match best {
                None => true,
                Some((_, bs, be, _)) => {
                    let best_len = be - bs;
                    let this_len = end - pos;
                    pos < bs
                        || (pos == bs && this_len > best_len)
                        || (pos == bs && this_len == best_len && key.len() > (be - bs))
                }
            };
            if is_better {
                best = Some((key, pos, end, val));
            }
        }
    }

    best
}

/// Excise a matched portion from a line: text_before + text_after.
fn excise(line: &str, start: usize, end: usize) -> String {
    let before = &line[..start];
    let after = &line[end..];
    format!("{}{}", before, after)
}

/// Strip PoB colour codes: ^8, ^7, ^x followed by 6 hex chars.
fn strip_colour_codes(line: &str) -> String {
    static COLOUR_RE: Lazy<Regex> = Lazy::new(|| Regex::new(r"\^[0-9]|\^x[0-9a-fA-F]{6}").unwrap());
    COLOUR_RE.replace_all(line, "").to_string()
}

/// Normalize a mod line: strip colour codes, lowercase, trim, append trailing space.
fn normalize(line: &str) -> String {
    let stripped = strip_colour_codes(line);
    let lower = stripped.to_lowercase();
    let trimmed = lower.trim().to_string();
    trimmed + " "
}

/// Main entry point: parse a mod line into a list of Mod structs.
///
/// Implements the full PoB parsing pipeline:
/// 1. Normalize
/// 2. Try specialModList (full-line match)
/// 3. Extract pre-flags
/// 4. Match form (INC/MORE/BASE/etc.)
/// 5. Extract mod tags (suffix conditions, up to 2 passes)
/// 6. Look up mod name
/// 7. Extract mod flags
/// 8. Construct mods
pub fn parse_mod_generated(
    line: &str,
    source: &ModSource,
    manual_handler: &dyn Fn(&str, &regex::Captures, &ModSource) -> Vec<Mod>,
) -> Vec<Mod> {
    let normalized = normalize(line);
    let norm = normalized.as_str();

    // Step 2: Try special mods (full-line match — must consume entire line)
    let special_patterns = &*SPECIAL_MOD_PATTERNS;
    for (i, re) in special_patterns.iter().enumerate() {
        if let Some(caps) = re.captures(norm.trim()) {
            // Check full-line match: the overall match must cover the entire trimmed line
            if let Some(m) = caps.get(0) {
                if m.start() == 0 && m.end() == norm.trim().len() {
                    return handle_special_mod(i, &caps, source, manual_handler);
                }
            }
        }
    }

    // From here on, work with the normalized line (with trailing space)
    let mut line = norm.to_string();

    // Step 3: Extract pre-flags
    let mut pre_flags = ModFlags::NONE;
    let mut pre_keyword_flags = KeywordFlags::NONE;
    let mut pre_tags: Vec<ModTag> = Vec::new();
    let mut add_to_minion = false;
    let mut add_to_skill = false;
    let mut add_to_aura = false;
    let mut new_aura = false;
    let mut apply_to_enemy = false;

    {
        let patterns = &*PRE_FLAG_PATTERNS;
        let pat_slice: Vec<(&Lazy<Regex>, &StaticPreFlagEntry)> =
            patterns.iter().map(|(r, e)| (r, e)).collect();
        // Build a slice-compatible view
        if let Some((idx, caps, start, end)) = scan_regex_for_pre_flags(&line, patterns) {
            let entry = &patterns[idx].1;
            pre_flags = pre_flags | entry.flags;
            pre_keyword_flags = pre_keyword_flags | entry.keyword_flags;
            for t in &entry.tags {
                pre_tags.push(t.to_mod_tag());
            }
            add_to_minion = entry.add_to_minion;
            add_to_skill = entry.add_to_skill;
            add_to_aura = entry.add_to_aura;
            new_aura = entry.new_aura;
            apply_to_enemy = entry.apply_to_enemy;
            line = excise(&line, start, end);
        }
    }

    // Step 4: Scan for modifier form
    let form_result = scan_form_patterns(&line);
    let (form_type, form_num, form_caps_extra) = match form_result {
        Some(v) => v,
        None => return vec![], // No form match = unparseable
    };
    // Excise the form match from the line
    if let Some((_idx, _caps, start, end)) = scan_regex(&line, &*FORM_PATTERNS) {
        line = excise(&line, start, end);
    }

    // Step 5: Extract mod tags (up to 2 passes)
    let mut mod_tags: Vec<ModTag> = Vec::new();
    {
        let patterns = &*MOD_TAG_PATTERNS;
        if let Some((idx, caps, start, end)) = scan_regex_for_mod_tags(&line, patterns) {
            let entry = &patterns[idx].1;
            for t in &entry.tags {
                mod_tags.push(t.to_mod_tag());
            }
            line = excise(&line, start, end);

            // Second pass
            if let Some((idx2, caps2, start2, end2)) = scan_regex_for_mod_tags(&line, patterns) {
                let entry2 = &patterns[idx2].1;
                for t in &entry2.tags {
                    mod_tags.push(t.to_mod_tag());
                }
                line = excise(&line, start2, end2);
            }
        }
    }

    // Step 6: Look up mod name
    let mod_name_result: Option<(Vec<String>, Vec<ModTag>)>;

    match &form_type {
        FormType::Pen => {
            // Use PEN_TYPES for name lookup
            if let Some((key, start, end, val)) = scan_plain(&line, &*PEN_TYPES) {
                mod_name_result = Some((vec![val.to_string()], vec![]));
                line = excise(&line, start, end);
                // Also scan modNameList to excise it
                if let Some((_, s2, e2, _)) = scan_plain(&line, &*MOD_NAME_MAP) {
                    line = excise(&line, s2, e2);
                }
            } else {
                return vec![];
            }
        }
        FormType::BaseCost => {
            if let Some((key, start, end, val)) = scan_plain_vec(&line, &*BASE_COST_TYPES) {
                mod_name_result = Some((val.clone(), vec![]));
                line = excise(&line, start, end);
                if let Some((_, s2, e2, _)) = scan_plain(&line, &*MOD_NAME_MAP) {
                    line = excise(&line, s2, e2);
                }
            } else {
                return vec![];
            }
        }
        FormType::TotalCost => {
            if let Some((key, start, end, val)) = scan_plain_vec(&line, &*COST_TYPES) {
                mod_name_result = Some((val.clone(), vec![]));
                line = excise(&line, start, end);
                if let Some((_, s2, e2, _)) = scan_plain(&line, &*MOD_NAME_MAP) {
                    line = excise(&line, s2, e2);
                }
            } else {
                return vec![];
            }
        }
        FormType::Flag => {
            // For FLAG form, the "value" from formCap[1] is looked up in flagTypes
            // Actually the FLAG form scans flagTypes first
            if let Some((key, start, end, val)) = scan_plain(&line, &*FLAG_TYPES) {
                line = excise(&line, start, end);
            }
            // Then scan modNameList
            if let Some((key, start, end, entry)) = scan_plain(&line, &*MOD_NAME_MAP) {
                let names: Vec<String> = entry.names.iter().map(|s| s.to_string()).collect();
                let tags: Vec<ModTag> = entry.tags.iter().map(|t| t.to_mod_tag()).collect();
                mod_name_result = Some((names, tags));
                line = excise(&line, start, end);
            } else {
                mod_name_result = None;
            }
        }
        _ => {
            // Standard name lookup
            if let Some((key, start, end, entry)) = scan_plain(&line, &*MOD_NAME_MAP) {
                let names: Vec<String> = entry.names.iter().map(|s| s.to_string()).collect();
                let tags: Vec<ModTag> = entry.tags.iter().map(|t| t.to_mod_tag()).collect();
                mod_name_result = Some((names, tags));
                line = excise(&line, start, end);
            } else {
                mod_name_result = None;
            }
        }
    }

    // Step 7: Extract mod flags (weapon/skill type)
    let mut mod_flag_flags = ModFlags::NONE;
    let mut mod_flag_kw = KeywordFlags::NONE;
    let mut mod_flag_tags: Vec<ModTag> = Vec::new();
    if let Some((key, start, end, entry)) = scan_plain(&line, &*MOD_FLAG_MAP) {
        mod_flag_flags = entry.flags;
        mod_flag_kw = entry.keyword_flags;
        for t in entry.tags.iter() {
            mod_flag_tags.push(t.to_mod_tag());
        }
        line = excise(&line, start, end);
    }

    // Step 8: Handle form-specific suffix and regen/degen/dmg lookups
    let mut mod_suffix = String::new();
    match &form_type {
        FormType::Base
        | FormType::Gain
        | FormType::Lose
        | FormType::Grants
        | FormType::GrantsGlobal
        | FormType::Removes => {
            if let Some((_, start, end, val)) = scan_plain(&line, &*SUFFIX_TYPES) {
                mod_suffix = val.to_string();
                line = excise(&line, start, end);
            }
        }
        _ => {}
    }

    // Step 9: Construct mods
    let (names, name_tags) = match mod_name_result {
        Some((n, t)) => (n, t),
        None => {
            // Special cases: RegenFlat/RegenPercent/DegenFlat/DegenPercent/Degen use captures for name
            match &form_type {
                FormType::RegenFlat | FormType::RegenPercent => {
                    let resource_type = form_caps_extra.as_deref().unwrap_or("");
                    if let Some(val) = REGEN_TYPES.get(resource_type) {
                        (val.clone(), vec![])
                    } else {
                        return vec![];
                    }
                }
                FormType::DegenFlat | FormType::DegenPercent => {
                    let resource_type = form_caps_extra.as_deref().unwrap_or("");
                    if let Some(val) = DEGEN_TYPES.get(resource_type) {
                        (val.clone(), vec![])
                    } else {
                        return vec![];
                    }
                }
                FormType::Degen => {
                    let dmg_type = form_caps_extra.as_deref().unwrap_or("");
                    if let Some(val) = DMG_TYPES.get(dmg_type) {
                        (vec![format!("{}Degen", val)], vec![])
                    } else {
                        return vec![];
                    }
                }
                FormType::Dmg | FormType::DmgAttacks | FormType::DmgSpells | FormType::DmgBoth => {
                    // Handled below in the damage section
                    (vec![], vec![])
                }
                _ => return vec![],
            }
        }
    };

    // Combine all flags and tags
    let combined_flags = pre_flags | mod_flag_flags;
    let combined_kw = pre_keyword_flags | mod_flag_kw;
    let mut all_tags: Vec<ModTag> = Vec::new();
    all_tags.extend(pre_tags);
    all_tags.extend(name_tags);
    all_tags.extend(mod_flag_tags);
    all_tags.extend(mod_tags);

    // Determine modType and modValue from form
    let mut mods = Vec::new();

    match &form_type {
        FormType::Inc => {
            for name in &names {
                mods.push(Mod {
                    name: format!("{}{}", name, mod_suffix),
                    mod_type: ModType::Inc,
                    value: ModValue::Number(form_num),
                    flags: combined_flags,
                    keyword_flags: combined_kw,
                    tags: all_tags.clone(),
                    source: source.clone(),
                });
            }
        }
        FormType::Red => {
            for name in &names {
                mods.push(Mod {
                    name: format!("{}{}", name, mod_suffix),
                    mod_type: ModType::Inc,
                    value: ModValue::Number(-form_num),
                    flags: combined_flags,
                    keyword_flags: combined_kw,
                    tags: all_tags.clone(),
                    source: source.clone(),
                });
            }
        }
        FormType::More => {
            for name in &names {
                mods.push(Mod {
                    name: format!("{}{}", name, mod_suffix),
                    mod_type: ModType::More,
                    value: ModValue::Number(form_num),
                    flags: combined_flags,
                    keyword_flags: combined_kw,
                    tags: all_tags.clone(),
                    source: source.clone(),
                });
            }
        }
        FormType::Less => {
            for name in &names {
                mods.push(Mod {
                    name: format!("{}{}", name, mod_suffix),
                    mod_type: ModType::More,
                    value: ModValue::Number(-form_num),
                    flags: combined_flags,
                    keyword_flags: combined_kw,
                    tags: all_tags.clone(),
                    source: source.clone(),
                });
            }
        }
        FormType::Base | FormType::Gain | FormType::Chance => {
            for name in &names {
                mods.push(Mod {
                    name: format!("{}{}", name, mod_suffix),
                    mod_type: ModType::Base,
                    value: ModValue::Number(form_num),
                    flags: combined_flags,
                    keyword_flags: combined_kw,
                    tags: all_tags.clone(),
                    source: source.clone(),
                });
            }
        }
        FormType::Lose | FormType::Removes => {
            for name in &names {
                mods.push(Mod {
                    name: format!("{}{}", name, mod_suffix),
                    mod_type: ModType::Base,
                    value: ModValue::Number(-form_num),
                    flags: combined_flags,
                    keyword_flags: combined_kw,
                    tags: all_tags.clone(),
                    source: source.clone(),
                });
            }
        }
        FormType::Grants | FormType::GrantsGlobal => {
            for name in &names {
                mods.push(Mod {
                    name: format!("{}{}", name, mod_suffix),
                    mod_type: ModType::Base,
                    value: ModValue::Number(form_num),
                    flags: combined_flags,
                    keyword_flags: combined_kw,
                    tags: all_tags.clone(),
                    source: source.clone(),
                });
            }
        }
        FormType::Flag => {
            for name in &names {
                mods.push(Mod {
                    name: format!("{}{}", name, mod_suffix),
                    mod_type: ModType::Flag,
                    value: ModValue::Bool(true),
                    flags: combined_flags,
                    keyword_flags: combined_kw,
                    tags: all_tags.clone(),
                    source: source.clone(),
                });
            }
        }
        FormType::Pen => {
            for name in &names {
                mods.push(Mod {
                    name: name.clone(),
                    mod_type: ModType::Base,
                    value: ModValue::Number(form_num),
                    flags: combined_flags,
                    keyword_flags: combined_kw,
                    tags: all_tags.clone(),
                    source: source.clone(),
                });
            }
        }
        FormType::Override => {
            for name in &names {
                mods.push(Mod {
                    name: format!("{}{}", name, mod_suffix),
                    mod_type: ModType::Override,
                    value: ModValue::Number(form_num),
                    flags: combined_flags,
                    keyword_flags: combined_kw,
                    tags: all_tags.clone(),
                    source: source.clone(),
                });
            }
        }
        FormType::RegenFlat => {
            for name in &names {
                mods.push(Mod {
                    name: name.clone(),
                    mod_type: ModType::Base,
                    value: ModValue::Number(form_num),
                    flags: combined_flags,
                    keyword_flags: combined_kw,
                    tags: all_tags.clone(),
                    source: source.clone(),
                });
            }
        }
        FormType::RegenPercent => {
            for name in &names {
                mods.push(Mod {
                    name: format!("{}Percent", name),
                    mod_type: ModType::Base,
                    value: ModValue::Number(form_num),
                    flags: combined_flags,
                    keyword_flags: combined_kw,
                    tags: all_tags.clone(),
                    source: source.clone(),
                });
            }
        }
        FormType::DegenFlat => {
            for name in &names {
                mods.push(Mod {
                    name: name.clone(),
                    mod_type: ModType::Base,
                    value: ModValue::Number(form_num),
                    flags: combined_flags,
                    keyword_flags: combined_kw,
                    tags: all_tags.clone(),
                    source: source.clone(),
                });
            }
        }
        FormType::DegenPercent => {
            for name in &names {
                mods.push(Mod {
                    name: format!("{}Percent", name),
                    mod_type: ModType::Base,
                    value: ModValue::Number(form_num),
                    flags: combined_flags,
                    keyword_flags: combined_kw,
                    tags: all_tags.clone(),
                    source: source.clone(),
                });
            }
        }
        FormType::Degen => {
            for name in &names {
                mods.push(Mod {
                    name: name.clone(),
                    mod_type: ModType::Base,
                    value: ModValue::Number(form_num),
                    flags: combined_flags,
                    keyword_flags: combined_kw,
                    tags: all_tags.clone(),
                    source: source.clone(),
                });
            }
        }
        FormType::TotalCost | FormType::BaseCost => {
            for name in &names {
                mods.push(Mod {
                    name: name.clone(),
                    mod_type: ModType::Base,
                    value: ModValue::Number(form_num),
                    flags: combined_flags,
                    keyword_flags: combined_kw,
                    tags: all_tags.clone(),
                    source: source.clone(),
                });
            }
        }
        FormType::Dmg | FormType::DmgAttacks | FormType::DmgSpells | FormType::DmgBoth => {
            // Damage range — need min/max from captures
            // form_num is first capture, form_caps_extra has the damage type
            // Actually for DMG, we have 3 captures: min, max, type
            // We already have form_num as the first cap, but we need the second and third
            // For now emit a simple version
            // TODO: proper damage range handling
            for name in &names {
                mods.push(Mod {
                    name: format!("{}{}", name, mod_suffix),
                    mod_type: ModType::Base,
                    value: ModValue::Number(form_num),
                    flags: combined_flags,
                    keyword_flags: combined_kw,
                    tags: all_tags.clone(),
                    source: source.clone(),
                });
            }
        }
        FormType::Doubled => {
            // Doubled = MORE(100) + OVERRIDE(1) with multiplier limit tag
            for name in &names {
                let name_str = format!("{}{}", name, mod_suffix);
                // MORE 100%
                let mut more_tags = all_tags.clone();
                more_tags.push(ModTag::Multiplier {
                    var: format!("{}Doubled", name_str),
                    div: 1.0,
                    limit: Some(100.0),
                    base: 0.0,
                });
                mods.push(Mod {
                    name: name_str.clone(),
                    mod_type: ModType::More,
                    value: ModValue::Number(100.0),
                    flags: combined_flags,
                    keyword_flags: combined_kw,
                    tags: more_tags,
                    source: source.clone(),
                });
                // OVERRIDE 1 for the multiplier
                mods.push(Mod {
                    name: format!("Multiplier:{}Doubled", name_str),
                    mod_type: ModType::Override,
                    value: ModValue::Number(1.0),
                    flags: combined_flags,
                    keyword_flags: combined_kw,
                    tags: all_tags.clone(),
                    source: source.clone(),
                });
            }
        }
    }

    // Handle addToMinion, addToAura, etc. wrappers
    if add_to_aura && !mods.is_empty() {
        let wrapped: Vec<Mod> = mods
            .into_iter()
            .map(|m| Mod {
                name: "ExtraAuraEffect".to_string(),
                mod_type: ModType::List,
                value: ModValue::String(format!("mod:{}", m.name)),
                flags: ModFlags::NONE,
                keyword_flags: KeywordFlags::NONE,
                tags: vec![],
                source: source.clone(),
            })
            .collect();
        return wrapped;
    }
    if new_aura && !mods.is_empty() {
        let wrapped: Vec<Mod> = mods
            .into_iter()
            .map(|m| Mod {
                name: "ExtraAura".to_string(),
                mod_type: ModType::List,
                value: ModValue::String(format!("mod:{}", m.name)),
                flags: ModFlags::NONE,
                keyword_flags: KeywordFlags::NONE,
                tags: vec![],
                source: source.clone(),
            })
            .collect();
        return wrapped;
    }
    if add_to_minion && !mods.is_empty() {
        let wrapped: Vec<Mod> = mods
            .into_iter()
            .map(|m| Mod {
                name: "MinionModifier".to_string(),
                mod_type: ModType::List,
                value: ModValue::String(format!("mod:{}", m.name)),
                flags: ModFlags::NONE,
                keyword_flags: KeywordFlags::NONE,
                tags: vec![],
                source: source.clone(),
            })
            .collect();
        return wrapped;
    }
    if apply_to_enemy && !mods.is_empty() {
        let wrapped: Vec<Mod> = mods
            .into_iter()
            .map(|m| Mod {
                name: "EnemyModifier".to_string(),
                mod_type: ModType::List,
                value: ModValue::String(format!("mod:{}", m.name)),
                flags: ModFlags::NONE,
                keyword_flags: KeywordFlags::NONE,
                tags: vec![],
                source: source.clone(),
            })
            .collect();
        return wrapped;
    }

    // Step 10: Reject if there is remaining non-whitespace text.
    //
    // Mirrors PoB's `modLine.extra` check in Item.lua:BuildModList() lines 1701-1724:
    //   if not modLine.extra then  -- skip mods with unparsed remaining text
    //
    // If after all parsing passes there are still unconsumed non-whitespace tokens,
    // the line is considered incompletely parsed and the mods are discarded.
    // Example: "2200 added Armour" → form "2200", name "Armour", remaining " added " →
    // "added" is not consumed, so the whole line is rejected.
    //
    // We re-run the parse up to the point we would have consumed the name, then
    // check what remains. Since `line` here is the residual after all consumption steps,
    // we check it directly.
    if line.chars().any(|c| !c.is_whitespace()) {
        // Try a second pass as PoB does (parseMod order=2).
        // For simplicity we re-check: if line still has non-whitespace, discard.
        // PoB's second pass changes nothing for this case (same result), so just discard.
        return vec![];
    }

    mods
}

/// Scan form patterns and extract form type + numeric value + extra capture.
fn scan_form_patterns(line: &str) -> Option<(FormType, f64, Option<String>)> {
    if let Some((idx, caps, _start, _end)) = scan_regex(line, &*FORM_PATTERNS) {
        let form = &FORM_PATTERNS[idx].1;
        let num_str = caps.get(1).map(|m| m.as_str()).unwrap_or("0");
        let num: f64 = num_str.parse().unwrap_or(0.0);
        let extra = caps.get(2).map(|m| m.as_str().to_string());
        Some((form.clone(), num, extra))
    } else {
        None
    }
}

/// Scan pre-flag patterns (from the Lazy<Vec<...>>).
fn scan_regex_for_pre_flags<'a>(
    line: &'a str,
    patterns: &[(Lazy<Regex>, StaticPreFlagEntry)],
) -> Option<(usize, regex::Captures<'a>, usize, usize)> {
    let mut best: Option<(usize, usize, usize, usize, usize)> = None;

    for (i, (re, _)) in patterns.iter().enumerate() {
        if let Some(m) = re.find(line) {
            let start = m.start();
            let end = m.end();
            let match_len = end - start;
            let pat_len = re.as_str().len();

            let is_better = match best {
                None => true,
                Some((_, bs, _be, bml, bpl)) => {
                    start < bs
                        || (start == bs && match_len > bml)
                        || (start == bs && match_len == bml && pat_len > bpl)
                }
            };

            if is_better {
                best = Some((i, start, end, match_len, pat_len));
            }
        }
    }

    if let Some((idx, start, end, _, _)) = best {
        let re = &patterns[idx].0;
        let caps = re.captures(line)?;
        Some((idx, caps, start, end))
    } else {
        None
    }
}

/// Scan mod tag patterns (from the Lazy<Vec<...>>).
fn scan_regex_for_mod_tags<'a>(
    line: &'a str,
    patterns: &[(Lazy<Regex>, StaticModTagEntry)],
) -> Option<(usize, regex::Captures<'a>, usize, usize)> {
    let mut best: Option<(usize, usize, usize, usize, usize)> = None;

    for (i, (re, _)) in patterns.iter().enumerate() {
        if let Some(m) = re.find(line) {
            let start = m.start();
            let end = m.end();
            let match_len = end - start;
            let pat_len = re.as_str().len();

            let is_better = match best {
                None => true,
                Some((_, bs, _be, bml, bpl)) => {
                    start < bs
                        || (start == bs && match_len > bml)
                        || (start == bs && match_len == bml && pat_len > bpl)
                }
            };

            if is_better {
                best = Some((i, start, end, match_len, pat_len));
            }
        }
    }

    if let Some((idx, start, end, _, _)) = best {
        let re = &patterns[idx].0;
        let caps = re.captures(line)?;
        Some((idx, caps, start, end))
    } else {
        None
    }
}

/// Find the earliest plain-text substring match among keys in a Lazy<HashMap<&str, Vec<String>>>.
fn scan_plain_vec<'a>(
    line: &str,
    map: &'a HashMap<&str, Vec<String>>,
) -> Option<(&'a str, usize, usize, &'a Vec<String>)> {
    let lower = line.to_lowercase();
    let mut best: Option<(&'a str, usize, usize, &'a Vec<String>)> = None;

    for (key, val) in map.iter() {
        if let Some(pos) = lower.find(key) {
            let end = pos + key.len();
            let is_better = match best {
                None => true,
                Some((_, bs, be, _)) => {
                    let best_len = be - bs;
                    let this_len = end - pos;
                    pos < bs
                        || (pos == bs && this_len > best_len)
                        || (pos == bs && this_len == best_len && key.len() > (be - bs))
                }
            };
            if is_better {
                best = Some((key, pos, end, val));
            }
        }
    }

    best
}

/// Number of templated (auto-generated handler) special mod entries.
pub const GENERATED_SPECIAL_COUNT: usize = 2060;
/// Number of manual handler special mod entries.
pub const MANUAL_SPECIAL_COUNT: usize = 31;
/// Total number of special mod entries.
pub const TOTAL_SPECIAL_COUNT: usize = 2091;
